<template>
    <label class="b-24-black" v-html="t('trial.title')"> </label>
    <div v-if="!isOffline">

        <div v-if="!hasActivePremiumPlan">
            <ul class="ps-0">
                <li class="list-group-item text-start my-3 b-16-black py-3 mx-4 rounded-3 planes px-1"
                    @click="selectedPlan = 'Mensual'" style="cursor: pointer;">
                    <div class="ps-5 form-check">
                        <input id="plan-m" class="form-check-input me-4" type="radio" name="plan" value="Mensual"
                            v-model="selectedPlan">
                        <label for="plan-m" class="form-check-label" v-html="t('trial.mensual')"
                            style="cursor: pointer;"></label>
                    </div>
                </li>
                <li class="list-group-item text-start my-3 b-16-black py-3 mx-4 rounded-3 planes px-1"
                    @click="selectedPlan = 'Semestral'" style="cursor: pointer;">
                    <div class="ps-5 form-check">
                        <input id="plan-s" class="form-check-input me-4" type="radio" name="plan" value="Semestral"
                            v-model="selectedPlan">
                        <label for="plan-s" class="form-check-label" v-html="t('trial.semestral')"
                            style="cursor: pointer;"></label>
                    </div>
                </li>
                <li class="list-group-item text-start my-3 b-16-black py-3 mx-4 rounded-3 planes px-1"
                    @click="selectedPlan = 'Anual'" style="cursor: pointer;">
                    <div class="ps-5 form-check">
                        <input id="plan-a" class="form-check-input me-4" type="radio" name="plan" value="Anual"
                            v-model="selectedPlan">
                        <label for="plan-a" class="form-check-label" v-html="t('trial.anual')"
                            style="cursor: pointer;"></label>
                    </div>
                </li>
            </ul>

            <div class="d-flex justify-content-center py-4">
                <button type="button" class="btn-black border-0 px-5 py-3 rounded-5" @click="proceedToCheckout"
                    :disabled="isLoading">
                    <span v-if="isLoading" class="spinner-border spinner-border-sm me-2" role="status"
                        aria-hidden="true"></span>
                    <span v-html="t('trial.pagar')"></span>
                </button>
            </div>
            <p v-if="errorMsg" class="text-danger text-center mt-2">{{ errorMsg }}</p>
        </div>

        <div v-else class="active-plan-container text-center py-4">
            <div class="card shadow-sm mx-4 border-0 rounded-4" style="background-color: #f8f9fa;">
                <div class="card-body py-5">
                    <h4 class="b-20-black mb-3" v-html="t('trial.active_plan_title')"></h4>
                    <h2 class="b-24-black mb-4" style="color: #6C5CE7;">{{ currentPlanName }}</h2>
                    <p class="r-16-gray mb-4">
                        <span v-html="t('trial.expires_on')"></span> <strong>{{ planExpiryDate }}</strong>
                    </p>
                    <button class="btn btn-outline-danger px-4 py-2 rounded-5 b-16-black mt-2"
                        @click="showCancelModal = true" :disabled="isCancelling">
                        <span v-if="isCancelling" class="spinner-border spinner-border-sm me-2"></span>
                        <span v-html="t('trial.cancel_btn')"></span>
                    </button>
                </div>
            </div>
        </div>

        <!-- Cancel Modal -->
        <div v-if="showCancelModal" class="modal-backdrop fade show" style="z-index: 1040;"></div>
        <div v-if="showCancelModal" class="modal fade show d-block" tabindex="-1" style="z-index: 1045;">
            <div class="modal-dialog modal-dialog-centered mx-4">
                <div class="modal-content rounded-4 border-0 shadow">
                    <div class="modal-body p-4 text-center">
                        <h5 class="b-20-black mb-4" v-html="t('trial.cancel_confirm')"></h5>
                        <div class="d-flex justify-content-center gap-3 mt-4">
                            <button type="button" class="btn btn-light px-4 py-2 rounded-5 b-16-black"
                                @click="showCancelModal = false" :disabled="isCancelling">No</button>
                            <button type="button" class="btn btn-danger px-4 py-2 rounded-5 b-16-black"
                                @click="cancelSubscription" :disabled="isCancelling">
                                <span v-if="isCancelling" class="spinner-border spinner-border-sm me-2"></span>
                                Sí
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>


    <div v-if="isOffline" class="offline-message d-flex flex-column align-items-center justify-content-center"
        style="min-height: 60vh;">
        <img src="../assets/btnAngerPulse.png" style="width: 200px; opacity: 0.5;" class="mb-4">
        <label class="b-24-gray text-center mb-3" v-html="t('offline.title')"></label>
        <p class="r-16-gray px-4 text-center" v-html="t('offline.trial')"></p>
        <p class="r-14-gray px-4 text-center mt-3" style="opacity: 0.7;" v-html="t('offline.subtitle')"></p>
    </div>

</template>


<script setup>
import { ref, onMounted, onBeforeUnmount } from 'vue'
import { useI18n } from 'vue-i18n'
import { API_BASE_URL } from '@/config/api'

const { t } = useI18n()
const isOffline = ref(!navigator.onLine)
const selectedPlan = ref('')
const isLoading = ref(false)
const errorMsg = ref('')

const hasActivePremiumPlan = ref(false)
const currentPlanName = ref('')
const planExpiryDate = ref('')
const showCancelModal = ref(false)
const isCancelling = ref(false)
const userEmail = ref('')

async function proceedToCheckout() {
    if (!selectedPlan.value) {
        errorMsg.value = t('trial.selecciona')
        return
    }

    const username = localStorage.getItem("token")
    if (!username) return

    isLoading.value = true
    errorMsg.value = ''

    try {
        const response = await fetch(`${API_BASE_URL}/api/stripe/create-checkout-session`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ planId: selectedPlan.value, username: username })
        })

        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`)
        }

        const data = await response.json()
        if (data && data.url) {
            window.location.href = data.url
        } else {
            throw new Error("Invalid response from server.")
        }
    } catch (e) {
        console.error(e)
        errorMsg.value = "An error occurred while connecting to Stripe."
    } finally {
        isLoading.value = false
    }
}

async function fetchUserPlan() {
    const username = localStorage.getItem("token")
    if (!username) return

    try {
        const response = await fetch(`${API_BASE_URL}/api/usuarios/GetUserInfo`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ username: username })
        })
        const data = await response.json()

        if (data && data.data) {
            const user = typeof data.data === 'string' ? JSON.parse(data.data) : data.data
            userEmail.value = user.Correo || user.email || ''
            console.log(user)
            const idPlan = parseInt(user.IdPlan, 10)

            // let parsedDate = new Date()
            // if (user.Fin && user.Fin.includes('/')) {
            //     const parts = user.Fin.split('/')
            //     parsedDate = new Date(parts[2], parts[1] - 1, parts[0])
            // } else if (user.Fin) {
            //     parsedDate = new Date(user.Fin)
            // }

            const now = new Date()
            now.setHours(0, 0, 0, 0)
            console.log(idPlan)
            if (idPlan > 0 && idPlan != 4) {
                hasActivePremiumPlan.value = true
                currentPlanName.value = t(`trial.plan_names.${idPlan}`)
                planExpiryDate.value = user.Fin
            }
        }
    } catch (e) {
        console.error("Error al obtener info del plan:", e)
    }
}

async function cancelSubscription() {
    const username = localStorage.getItem("token")
    if (!username) return

    isCancelling.value = true
    try {
        const response = await fetch(`${API_BASE_URL}/api/stripe/cancel-subscription`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ username: username, email: userEmail.value })
        })

        if (response.ok) {
            showCancelModal.value = false
            hasActivePremiumPlan.value = false
            window.location.reload()
        } else {
            const errData = await response.json()
            console.error(errData)
            alert("Error al cancelar la membresía")
        }
    } catch (e) {
        console.error("Cancellation error:", e)
        alert("Error de conexión al cancelar")
    } finally {
        isCancelling.value = false
    }
}

onMounted(() => {
    fetchUserPlan()
    window.addEventListener('online', updateOnlineStatus)
    window.addEventListener('offline', updateOnlineStatus)
})

function updateOnlineStatus() {
    isOffline.value = !navigator.onLine
}

onBeforeUnmount(() => {
    window.removeEventListener('online', updateOnlineStatus)
    window.removeEventListener('offline', updateOnlineStatus)
})
</script>